$ErrorActionPreference="Continue";$Root=Split-Path -Parent $MyInvocation.MyCommand.Path;$PidFile=Join-Path (Join-Path $Root "state") "startup-ui-pids.json";if(!(Test-Path -LiteralPath $PidFile)){Write-Host "Startup UI state: not started by detached launcher.";return};$state=Get-Content -LiteralPath $PidFile -Raw|ConvertFrom-Json;$pidAlive=if($state.pid){[bool](Get-Process -Id ([int]$state.pid) -ErrorAction SilentlyContinue)}else{$false};$healthOk=$false;$healthUrl="http://127.0.0.1:$($state.port)/api/snapshot";try{$response=Invoke-WebRequest -UseBasicParsing -Uri $healthUrl -TimeoutSec 3;$healthOk=$response.StatusCode -eq 200}catch{};Write-Host "Startup UI";Write-Host "  URL: $($state.url)";Write-Host "  PID: $($state.pid) alive=$pidAlive";Write-Host "  Health: $healthUrl ok=$healthOk";Write-Host "  StartedAt: $($state.startedAt)";Write-Host "  Logs: $($state.logs.stdout) ; $($state.logs.stderr)"
